class Solution:
    def numsSameConsecDiff(self, n, k):
        level = [[d] for d in range(1, 10)]
        for _ in range(n - 1):
            nxt = []
            for seq in level:
                last = seq[-1]
                for c in {last + k, last - k}:
                    if 0 <= c <= 9:
                        nxt.append(seq + [c])
            level = nxt
        res = []
        for seq in level:
            num = 0
            for d in seq:
                num = num * 10 + d
            res.append(num)
        return res

