class Solution:
    def numsSameConsecDiff(self, n, k):
        res = []
        def build(num, length, last):
            if length == n:
                res.append(num)
                return
            nexts = {last + k, last - k}
            for d in nexts:
                if 0 <= d <= 9:
                    build(num * 10 + d, length + 1, d)
        for first in range(1, 10):
            build(first, 1, first)
        return res

