var numsSameConsecDiff = function(n, k) {
    const res = [];
    const build = (num, length, last) => {
        if (length === n) { res.push(num); return; }
        const nexts = new Set([last + k, last - k]);
        for (const d of nexts) {
            if (d >= 0 && d <= 9) build(num * 10 + d, length + 1, d);
        }
    };
    for (let first = 1; first <= 9; first++) build(first, 1, first);
    return res;
};
